input.command:
powershell -NoProfile -Command "
$base = 'C:\Users\1\Downloads\deepseek_data-2026-05-17\output_md'
$folders = @('01_AI与编程开发','02_计算机与操作系统','03_健康与医学','04_游戏与娱乐','05_数学与自然科学','06_苹果生态与设备','07_生活与消费','08_职业与职场','09_硬件与工程','10_人文与知识')
$results = @()
foreach ($f in $folders) {
    $dir = Join-Path $base $f
    Get-ChildItem $dir -Filter *.md | ForEach-Object {
        $lines = (Get-Content $_.FullName | Measure-Object -Line).Lines
        $rel = $f + '\' + $_.Name
        $results += [PSCustomObject]@{ path = $rel; lines = $lines }
    }
}
$results | Sort-Object lines -Descending | ConvertTo-Json -Depth 2 | Out-File -Encoding UTF8 (Join-Path $base '_scan_new.json')
Write-Output ('Total files: ' + $results.Count)
"

